// +esm 的 default 导出即 OSMD 命名空间(named 导出 opensheetmusicdisplay 在 ESM 下为 undefined,已浏览器实测)
import OSMD from 'https://cdn.jsdelivr.net/npm/opensheetmusicdisplay@2/+esm';
const el = document.getElementById('score'); el.style.minHeight = '480px';
const osmd = new OSMD.OpenSheetMusicDisplay(el, { backend: 'svg', autoResize: true, drawTitle: data.drawTitle ?? true });
await osmd.load(data.musicxml);
osmd.render();

